function generateSecureToken(byteLength = 32) {
  return crypto.randomBytes(byteLength).toString('hex');
}

function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

/**
 * Creates a secure "Remember Me" token using the split-token pattern:
 * - selector: used to look up the token in the database (not secret)
 * - validator: the secret part, only a hash is stored server-side
 * 
 * The cookie stores: selector:validator
 * The database stores: selector -> hash(validator)
 * 
 * This way, even if the database is compromised, attackers can't forge cookies.
 */
function createRememberMeToken(username) {
  const selector = generateSecureToken(16);
  const validator = generateSecureToken(32);
  const hashedValidator = hashToken(validator);

  const THIRTY_DAYS_MS = 30 * 24 * 60 * 60 * 1000;
  const expires = new Date(Date.now() + THIRTY_DAYS_MS);

  // Store in database (replace with real DB query)
  rememberMeTokens[selector] = {
    hashedValidator,
    username,
    expires
  };

  // Return the cookie value: selector:validator
  return {
    cookieValue: `${selector}:${validator}`,
    expires
  };
}

/**
 * Validates a "Remember Me" cookie and returns the username if valid.
 * Uses constant-time comparison to prevent timing attacks.
 */
function validateRememberMeToken(cookieValue) {
  if (!cookieValue || typeof cookieValue !== 'string') {
    return null;
  }

  const parts = cookieValue.split(':');
  if (parts.length !== 2) {
    return null;
  }

  const [selector, validator] = parts;
  const tokenRecord = rememberMeTokens[selector];

  if (!tokenRecord) {
    return null;
  }

  // Check expiration
  if (new Date() > new Date(tokenRecord.expires)) {
    delete rememberMeTokens[selector];
    return null;
  }

  // Constant-time comparison of hashed validator
  const hashedValidator = hashToken(validator);
  const storedHash = tokenRecord.hashedValidator;

  const isValid = crypto.timingSafeEqual(
    Buffer.from(hashedValidator, 'hex'),
    Buffer.from(storedHash, 'hex')
  );

  if (!isValid) {
    // Possible token theft — invalidate all tokens for this user
    invalidateAllTokensForUser(tokenRecord.username);
    return null;
  }

  return tokenRecord.username;
}

/**
 * Invalidate a specific token by selector
 */
function invalidateToken(cookieValue) {
  if (!cookieValue) return;
  const selector = cookieValue.split(':')[0];
  delete rememberMeTokens[selector];
}

/**
 * Invalidate all remember-me tokens for a user (e.g., on password change or theft detection)
 */
function invalidateAllTokensForUser(username) {
  for (const selector of Object.keys(rememberMeTokens)) {
    if (rememberMeTokens[selector].username === username) {
      delete rememberMeTokens[selector];
    }
  }
}

/**
 * Token rotation: after successful auto-login, issue a new token
 * and invalidate the old one. This limits the window of token theft.
 */
function rotateRememberMeToken(oldCookieValue, username) {
  invalidateToken(oldCookieValue);
  return createRememberMeToken(username);
}

// ============================================================
// Middleware: Auto-login via Remember Me cookie
// ============================================================
function autoLoginMiddleware(req, res, next) {
  // If already logged in via session, skip
  if (req.session && req.session.username) {
    req.user = { username: req.session.username };
    return next();
  }

  // Simple session simulation via a session cookie
  if (req.cookies && req.cookies.session_user) {
    req.user = { username: req.cookies.session_user };
    return next();
  }

  // Try auto-login via remember_me cookie
  const rememberMeCookie = req.cookies ? req.cookies.remember_me : null;

  if (rememberMeCookie) {
    const username = validateRememberMeToken(rememberMeCookie);

    if (username && users[username]) {
      console.log(`[Auto-Login] User "${username}" authenticated via Remember Me token`);

      // Rotate the token for security
      const newToken = rotateRememberMeToken(rememberMeCookie, username);

      // Set new remember_me cookie
      res.cookie('remember_me', newToken.cookieValue, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production', // HTTPS only in production
        sameSite: 'lax',
        maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
        path: '/'
      });

      // Set session cookie
      res.cookie('session_user', username, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        path: '/'
      });

      req.user = { username };
      return next();
    } else {
      // Invalid token — clear the cookie
      res.clearCookie('remember_me');
    }
  }

  req.user = null;
  next();
}

