// Login handler
app.post('/login', async (req, res) => {
  const { username, password, rememberMe } = req.body;

  // Validate input
  if (!username || !password) {
    return res.status(400).send('Username and password are required.');
  }

  // Look up user
  const user = users[username.toLowerCase()];
  if (!user) {
    // Use generic message to prevent username enumeration
    return res.status(401).send('Invalid username or password. <a href="/login">Try again</a>');
  }

  // Verify password
  const passwordValid = await bcrypt.compare(password, user.passwordHash);
  if (!passwordValid) {
    return res.status(401).send('Invalid username or password. <a href="/login">Try again</a>');
  }

  console.log(`[Login] User "${username}" logged in successfully. Remember Me: ${!!rememberMe}`);

  // Set session cookie
  res.cookie('session_user', user.username, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/'
  });

  // If "Remember Me" is checked, create a secure long-lived token
  if (rememberMe) {
    const token = createRememberMeToken(user.username);

    res.cookie('remember_me', token.cookieValue, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
      path: '/'
    });

    console.log(`[Login] Remember Me token created for "${username}", expires: ${token.expires}`);
  }

  res.redirect('/dashboard');
});

